//! Spec-compliance tests: Bookmarks (ISO 29500-1 §17.13.6)
//!
//! These tests verify our implementation of bookmark parsing against specific
//! OOXML bookmark constructs.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use std::fs;

use stemma::{
    CanonDoc, DecorationNode, DecorationType, DocxRuntime, ExportMode, InlineNode, SimpleRuntime,
    TransactionMeta,
};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/bookmarks";

// ── helpers ──────────────────────────────────────────────────────────────
/// Collect all Decoration inlines with DecorationType::Bookmark from a paragraph.
fn bookmark_decorations(p: &stemma::ParagraphNode) -> Vec<&DecorationNode> {
    p.all_inlines()
        .filter_map(|inline| match inline {
            InlineNode::Decoration(d) if d.kind == DecorationType::Bookmark => Some(d.as_ref()),
            _ => None,
        })
        .collect()
}

/// Collect all Decoration inlines from an entire document.
fn all_bookmark_decorations(doc: &CanonDoc) -> Vec<&DecorationNode> {
    let paras = common::all_paragraphs(doc);
    paras.iter().flat_map(|p| bookmark_decorations(p)).collect()
}

// ── basic bookmark ───────────────────────────────────────────────────────

/// ISO 29500-1 §17.13.6.2/1: bookmarkStart and bookmarkEnd define a
/// bookmark range. They should produce Decoration inlines with
/// DecorationType::Bookmark.
#[test]
fn spec_bookmark_parsed_as_decoration() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "basic-bookmark");

    let decorations = all_bookmark_decorations(&doc);

    assert!(
        decorations.len() >= 2,
        "basic-bookmark should produce at least 2 bookmark Decoration nodes \
         (one for bookmarkStart, one for bookmarkEnd), got {}",
        decorations.len()
    );

    // All should be Bookmark type
    for d in &decorations {
        assert_eq!(
            d.kind,
            DecorationType::Bookmark,
            "bookmark decoration should have DecorationType::Bookmark, got {:?}",
            d.kind
        );
    }
}

/// ISO 29500-1 §17.13.6.2/1: Both bookmarkStart and bookmarkEnd markers
/// must be present in the parsed document.
#[test]
fn spec_bookmark_start_end_both_present() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "basic-bookmark");

    let paras = common::all_paragraphs(&doc);
    assert!(!paras.is_empty(), "should have at least one paragraph");

    let decorations = bookmark_decorations(paras[0]);

    // We expect at least 2 decoration nodes (start + end) in the paragraph
    assert!(
        decorations.len() >= 2,
        "basic-bookmark paragraph should have at least 2 bookmark decorations \
         (bookmarkStart + bookmarkEnd), got {}. \
         Inlines: {:?}",
        decorations.len(),
        paras[0]
            .all_inlines()
            .map(|i| format!("{:?}", std::mem::discriminant(i)))
            .collect::<Vec<_>>()
    );
}

// ── multi-paragraph bookmark ─────────────────────────────────────────────

/// ISO 29500-1 §17.13.6.2/1: A bookmark range can span multiple paragraphs.
/// bookmarkStart should appear in paragraph 1 and bookmarkEnd in paragraph 2.
#[test]
fn spec_multi_paragraph_bookmark_spans_blocks() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "multi-paragraph-bookmark");

    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 2,
        "multi-paragraph-bookmark should have at least 2 paragraphs, got {}",
        paras.len()
    );

    let decos_p1 = bookmark_decorations(paras[0]);
    let decos_p2 = bookmark_decorations(paras[1]);

    // bookmarkStart should be in paragraph 1
    assert!(
        !decos_p1.is_empty(),
        "paragraph 1 should contain bookmark decoration(s) (bookmarkStart). \
         Inlines in para 1: {:?}",
        paras[0]
            .all_inlines()
            .map(|i| format!("{:?}", std::mem::discriminant(i)))
            .collect::<Vec<_>>()
    );

    // bookmarkEnd should be in paragraph 2
    assert!(
        !decos_p2.is_empty(),
        "paragraph 2 should contain bookmark decoration(s) (bookmarkEnd). \
         Inlines in para 2: {:?}",
        paras[1]
            .all_inlines()
            .map(|i| format!("{:?}", std::mem::discriminant(i)))
            .collect::<Vec<_>>()
    );
}

// ── nested bookmarks ─────────────────────────────────────────────────────

/// ISO 29500-1 §17.13.6: Bookmark ranges may overlap. Two overlapping
/// bookmark ranges should both produce decoration nodes.
#[test]
fn spec_nested_bookmarks() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "nested-bookmarks");

    let paras = common::all_paragraphs(&doc);
    assert!(!paras.is_empty(), "should have at least one paragraph");

    let decorations = bookmark_decorations(paras[0]);

    // We expect 4 decoration nodes: bookmarkStart(A), bookmarkStart(B),
    // bookmarkEnd(A), bookmarkEnd(B)
    assert!(
        decorations.len() >= 4,
        "nested-bookmarks should produce at least 4 bookmark Decoration nodes \
         (2 starts + 2 ends for overlapping bookmarks A and B), got {}",
        decorations.len()
    );
}

// ── bookmark roundtrip ───────────────────────────────────────────────────

/// ISO 29500-1 §17.13.6: Bookmarks must survive the import -> redline
/// export -> reimport pipeline.
#[test]
fn spec_bookmark_survives_redline_roundtrip() {
    let path = format!("{FIXTURES}/bookmark-roundtrip/input.docx");
    let bytes = fs::read(&path).unwrap_or_else(|e| panic!("read {path}: {e}"));

    let runtime = SimpleRuntime::new();
    let import = runtime.import_docx(&bytes).expect("import");

    // Verify bookmarks exist before roundtrip
    let view_before = runtime.view(&import.doc_handle).expect("view");
    let decos_before = all_bookmark_decorations(&view_before.canonical);
    assert!(
        decos_before.len() >= 2,
        "bookmark-roundtrip should have at least 2 bookmark decorations before roundtrip, got {}",
        decos_before.len()
    );

    // Diff against itself (identity) and apply redline
    let import2 = runtime.import_docx(&bytes).expect("import2");
    let meta = TransactionMeta {
        author: "spec_bookmarks".to_string(),
        reason: Some("bookmark roundtrip test".to_string()),
        timestamp_utc: Some("2025-01-01T00:00:00Z".to_string()),
    };
    let _ = runtime.diff_and_redline(&import.doc_handle, &import2.doc_handle, meta);

    // Export and re-import
    let exported = runtime
        .export_docx(&import.doc_handle, ExportMode::Redline)
        .expect("export");

    let verify = SimpleRuntime::new();
    let reimport = verify.import_docx(&exported).expect("re-import");
    let view = verify.view(&reimport.doc_handle).expect("view");

    let decos_after = all_bookmark_decorations(&view.canonical);
    assert!(
        decos_after.len() >= 2,
        "Bookmark decorations should survive the redline pipeline. \
         Had {} before, got {} after roundtrip. \
         Bookmarks may have been lost during export/reimport.",
        decos_before.len(),
        decos_after.len()
    );
}
